const items = $input.all();
const results = [];

function esc(v) { if (v === null || v === undefined) return null; return String(v).replace(/'/g, "''"); }

for (const item of items) {
  const o = item.json;
  const agency = String(o.agency || '').toUpperCase();
  const title = String(o.opp_title || '').toUpperCase();
  const naics = String(o.naics_code || '');
  const rawL1 = String(o.level_1 || '');
  const rawL2 = String(o.level_2 || o.agency || '');

  let L1 = 'Unknown';
  const firstSeg = rawL1.indexOf('.') > 0 ? rawL1.split('.')[0].trim() : rawL1;
  const lower1 = firstSeg.toLowerCase();
  const agLower = agency.toLowerCase();
  const allText = (lower1 + ' ' + agLower).toLowerCase();

  if (allText.includes('dept of defense') || allText.includes('department of defense') || ['dod','dow','department of war'].includes(lower1)) L1 = 'Department of War';
  else if (allText.includes('veterans affairs') || lower1 === 'va') L1 = 'Department of Veterans Affairs';
  else if (allText.includes('homeland security') || lower1 === 'dhs') L1 = 'Department of Homeland Security';
  else if (allText.includes('treasury')) L1 = 'Department of the Treasury';
  else if (allText.includes('interior') || allText.includes('national park') || allText.includes('fish and wildlife') || allText.includes('bureau of reclamation')) L1 = 'Department of the Interior';
  else if (allText.includes('agriculture') || allText.includes('forest service') || allText.includes('usda')) L1 = 'Department of Agriculture';
  else if (allText.includes('justice') || allText.includes('federal prison') || allText.includes('doj') || allText.includes('fbi') || allText.includes('dea')) L1 = 'Department of Justice';
  else if (allText.includes('energy') || allText.includes('nnsa')) L1 = 'Department of Energy';
  else if (allText.includes('commerce') || allText.includes('noaa') || allText.includes('nist')) L1 = 'Department of Commerce';
  else if (allText.includes('transportation') || allText.includes('faa') || allText.includes('fhwa')) L1 = 'Department of Transportation';
  else if (allText.includes('state, department') || (allText.includes('state') && allText.includes('department of') && !allText.includes('united states'))) L1 = 'Department of State';
  else if (allText.includes('health and human') || allText.includes('hhs') || allText.includes('nih') || allText.includes('cdc') || allText.includes('cms')) L1 = 'Department of Health and Human Services';
  else if (allText.includes('housing') || allText.includes('hud')) L1 = 'Department of Housing and Urban Development';
  else if (allText.includes('nasa') || allText.includes('aeronautics')) L1 = 'National Aeronautics and Space Administration';
  else if (allText.includes('gsa') || allText.includes('general services')) L1 = 'General Services Administration';
  else if (allText.includes('intelligence') || allText.includes('cia') || allText.includes('odni')) L1 = 'Intelligence Community';
  else {
    const dowKw = ['army','navy','naval','marine','air force','space force','socom','tradoc','inscom','cybercom','disa','darpa','dla','mda','dtra','nsa','nga','dia','centcom','eucom','indopacom','africom','northcom','southcom','stratcom','transcom','spacecom','devcom','cecom','navair','navsea','aflcmc','afrl','peo ','usasoc','jsoc','marsoc','afsoc','navspecwar'];
    for (const kw of dowKw) { if (allText.includes(kw)) { L1 = 'Department of War'; break; } }
  }

  let L2 = '';
  const parts = rawL2.split('.');
  if (parts.length >= 2 && parts[0].toUpperCase().includes('DEPT OF')) {
    const branch = parts[1].trim();
    const bLower = branch.toLowerCase();
    const branchMap = {
      'dept of the army': 'Dept of the Army', 'dept of the navy': 'Dept of the Navy',
      'dept of the air force': 'Dept of the Air Force', 'defense logistics agency': 'DLA',
      'defense information systems agency': 'DISA', 'defense advanced research projects agency': 'DARPA',
      'defense intelligence agency': 'DIA', 'missile defense agency': 'MDA',
      'defense threat reduction agency': 'DTRA', 'defense contract management agency': 'DCMA',
      'defense counterintelligence and security agency': 'DCSA', 'defense health agency': 'DHA',
      'national geospatial-intelligence agency': 'NGA', 'national security agency': 'NSA',
      'office of the secretary of defense': 'OSD', 'us special operations command': 'USSOCOM',
      'us cyber command': 'USCYBERCOM', 'us transportation command': 'USTRANSCOM',
      'dod washington headquarters services': 'DoD WHS', 'united states marine corps': 'USMC'
    };
    L2 = branchMap[bLower] || branch.split(' ').map(w => w.length <= 3 && w === w.toUpperCase() ? w : w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');
  } else if (!rawL2.includes('.')) {
    L2 = rawL2;
  } else {
    L2 = parts.length >= 2 ? parts[1].trim() : parts[0].trim();
    L2 = L2.split(' ').map(w => w.length <= 3 && w === w.toUpperCase() ? w : w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()).join(' ');
  }
  if (!L2 || L2 === 'Unknown' || L2 === 'Unassigned') L2 = o.agency || 'Unassigned';

  let bu = 'Review_Required';
  const allUpper = (title + ' ' + agency + ' ' + naics).toUpperCase();
  const enableKw = ['CLOUD','AI','ML','DATA ANALYTICS','MODERNIZATION','DIGITAL TRANSFORMATION','SOFTWARE','AGILE','DEVOPS','DEVSECOPS','PLATFORM','SAAS','MACHINE LEARNING','ARTIFICIAL INTELLIGENCE'];
  const eisKw = ['ENTERPRISE','INFRASTRUCTURE','CYBERSECURITY','NETWORK','SIEM','ZERO TRUST','IDENTITY','SETA','SYSTEMS ENGINEERING','C5ISR','C4ISR','IT SUPPORT'];
  const protectKw = ['PHYSICAL SECURITY','THREAT ASSESSMENT','PROTECTIVE','FORCE PROTECTION','ANTITERRORISM','ACCESS CONTROL','SURVEILLANCE'];
  const trainKw = ['TRAINING','SIMULATION','EDUCATION','INSTRUCTOR','COURSEWARE','LVC','CONSTRUCTIVE','VIRTUAL TRAINING','FLIGHT SCHOOL','JLCCTC','TADSS'];

  let buScore = {Enable:0, EIS:0, Protect:0, Train:0};
  for (const kw of enableKw) if (allUpper.includes(kw)) buScore.Enable++;
  for (const kw of eisKw) if (allUpper.includes(kw)) buScore.EIS++;
  for (const kw of protectKw) if (allUpper.includes(kw)) buScore.Protect++;
  for (const kw of trainKw) if (allUpper.includes(kw)) buScore.Train++;

  const maxBU = Object.entries(buScore).sort((a,b) => b[1]-a[1])[0];
  if (maxBU[1] > 0) bu = maxBU[0];

  const ouVal = bu === 'Enable' ? 'OU3' : bu === 'EIS' ? 'OU3' : bu === 'Protect' ? 'OU2' : bu === 'Train' ? 'OU1' : null;

  // Build safe SQL with escaped values
  let sql = "UPDATE gda_opportunity_tracker SET level_1 = '" + esc(L1) + "', level_2 = '" + esc(L2) + "'";
  if (ouVal) sql += ", assigned_ou = '" + esc(ouVal) + "'";
  sql += " WHERE id = " + parseInt(o.id, 10);

  results.push({
    json: {
      id: o.id,
      level_1: L1,
      level_2: L2,
      assigned_ou: ouVal,
      business_unit: bu,
      update_sql: sql
    }
  });
}

return results;
